2568 /// Tries to reduce a pattern that arises when calculating the remainder of the
2569 /// Euclidean division. When the divisor is a power of two and is guaranteed not
2570 /// to be negative, a signed remainder can be folded with a bitwise and.
2571 ///
2572 /// (x % n) < 0 ? (x % n) + n : (x % n)
2573 ///    -> x & (n - 1)
2574 static Instruction *foldSelectWithSRem(SelectInst &SI, InstCombinerImpl &IC,
2575                                        IRBuilderBase &Builder) {
2576   Value *CondVal = SI.getCondition();
2577   Value *TrueVal = SI.getTrueValue();
2578   Value *FalseVal = SI.getFalseValue();
2579 
2580   ICmpInst::Predicate Pred;
2581   Value *Op, *RemRes, *Remainder;
2582   const APInt *C;
2583   bool TrueIfSigned = false;
2584 
2585   if (!(match(CondVal, m_ICmp(Pred, m_Value(RemRes), m_APInt(C))) &&
2586         IC.isSignBitCheck(Pred, *C, TrueIfSigned)))
2587     return nullptr;
2588 
2589   // If the sign bit is not set, we have a SGE/SGT comparison, and the operands
2590   // of the select are inverted.
2591   if (!TrueIfSigned)
2592     std::swap(TrueVal, FalseVal);
2593 
2594   auto FoldToBitwiseAnd = [&](Value *Remainder) -> Instruction * {
2595     Value *Add = Builder.CreateAdd(
2596         Remainder, Constant::getAllOnesValue(RemRes->getType()));
2597     return BinaryOperator::CreateAnd(Op, Add);
2598   };
2599 
2600   // Match the general case:
2601   // %rem = srem i32 %x, %n
2602   // %cnd = icmp slt i32 %rem, 0
2603   // %add = add i32 %rem, %n
2604   // %sel = select i1 %cnd, i32 %add, i32 %rem
2605   if (match(TrueVal, m_Add(m_Value(RemRes), m_Value(Remainder))) &&
2606       match(RemRes, m_SRem(m_Value(Op), m_Specific(Remainder))) &&
2607       IC.isKnownToBeAPowerOfTwo(Remainder, /*OrZero*/ true) &&
2608       FalseVal == RemRes)
2609     return FoldToBitwiseAnd(Remainder);
2610 
2611   // Match the case where the one arm has been replaced by constant 1:
2612   // %rem = srem i32 %n, 2
2613   // %cnd = icmp slt i32 %rem, 0
2614   // %sel = select i1 %cnd, i32 1, i32 %rem
2615   if (match(TrueVal, m_One()) &&
2616       match(RemRes, m_SRem(m_Value(Op), m_SpecificInt(2))) &&
2617       FalseVal == RemRes)
2618     return FoldToBitwiseAnd(ConstantInt::get(RemRes->getType(), 2));
2619 
2620   return nullptr;
2621 }
